397→const FIXTURE_BUILDERS = {
398→  kitchenTop: buildKitchenTopFixture,
399→  toilet: buildToiletFixture,
400→  lavatory: buildLavatoryFixture,
401→  table: buildTableFixture,
402→  tv: buildTvFixture,
403→  sofa: buildSofaFixture,
404→  bed: buildBedFixture,
405→};
