  1→import * as THREE from 'three';
  2→import { createMaterialPalette, disposeMaterialPalette } from './materials';
  3→import { disposeScene } from './disposeScene';
  4→import { createInspectNavigation } from './createInspectNavigation';
  5→import { createWalkNavigation } from './createWalkNavigation';
  6→import { CLICK_DISTANCE_THRESHOLD } from './previewConfig';
  7→import { createGrid, descriptorBoundsToWorldBox } from './previewCameraMath';
  8→
  9→export function createPreviewViewport(container) {
 10→  const materialPalette = createMaterialPalette();
 11→  const scene = new THREE.Scene();
 12→  scene.background = null;
 13→  const raycaster = new THREE.Raycaster();
 14→  const timer = new THREE.Timer();
 15→  timer.connect(document);
 16→
 17→  const camera = new THREE.PerspectiveCamera(42, 1, 10, 100000);
 18→  const renderer = new THREE.WebGLRenderer({
 19→    antialias: true,
 20→    alpha: true,
 21→    powerPreference: 'high-performance',
 22→  });
 23→  renderer.outputColorSpace = THREE.SRGBColorSpace;
 24→  renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
 25→  renderer.setSize(container.clientWidth || 1, container.clientHeight || 1, false);
 26→  renderer.domElement.style.width = '100%';
 27→  renderer.domElement.style.height = '100%';
 28→  renderer.domElement.style.display = 'block';
 29→  container.appendChild(renderer.domElement);
 30→
 31→  const inspectNavigation = createInspectNavigation({
 32→    camera,
 33→    domElement: renderer.domElement,
 34→  });
 35→
 36→  scene.add(new THREE.AmbientLight(0xffffff, 0.72));
 37→  scene.add(new THREE.HemisphereLight(0xdde7f4, 0xe6ded0, 0.7));
 38→  const keyLight = new THREE.DirectionalLight(0xffffff, 1.05);
 39→  keyLight.position.set(3500, 5000, 2000);
 40→  scene.add(keyLight);
 41→
 42→  let animationFrame = 0;
 43→  let worldRoot = null;
 44→  let gridHelper = null;
 45→  let currentBounds = null;
 46→  let pickHandler = null;
 47→  let pickContext = { activeFloorId: null };
 48→  let pointerDown = null;
 49→  let navigationMode = 'inspect';
 50→  let walkUiHandler = null;
 51→  let walkExitHandler = null;
 52→  let inspectState = null;
 53→  let activeFloorContext = {
 54→    floorId: null,
 55→    spawn: null,
 56→  };
 57→  const walkPoseByFloorId = new Map();
 58→  const walkNavigation = createWalkNavigation({
 59→    camera,
 60→    domElement: renderer.domElement,
 61→    onStateChange: () => {
 62→      emitWalkUiState();
 63→    },
 64→    onExitRequested: () => {
 65→      setNavigationMode('inspect');
 66→      walkExitHandler?.();
 67→    },
 68→  });
 69→
 70→  const emitWalkUiState = () => {
 71→    walkUiHandler?.({
 72→      navigationMode,
 73→      isLocked: navigationMode === 'walk' && walkNavigation.isLocked(),
 74→      canLock: navigationMode === 'walk',
 75→    });
 76→  };
 77→
 78→  const saveCurrentWalkPose = () => {
 79→    if (!activeFloorContext.floorId) return;
 80→    walkPoseByFloorId.set(activeFloorContext.floorId, walkNavigation.capturePose());
 81→  };
 82→
 83→  const restoreWalkPose = ({ forceSpawn = false } = {}) => {
 84→    if (!activeFloorContext.floorId) return;
 85→
 86→    const rememberedPose = !forceSpawn
 87→      ? walkPoseByFloorId.get(activeFloorContext.floorId)
 88→      : null;
 89→
 90→    if (rememberedPose) {
 91→      walkNavigation.restorePose(rememberedPose);
 92→      return;
 93→    }
 94→
 95→    const spawn = activeFloorContext.spawn;
 96→    if (!spawn?.position || !spawn.lookAt) return;
 97→
 98→    walkNavigation.restorePose({
 99→      position: [spawn.position.x, spawn.position.y, spawn.position.z],
100→      lookAt: [spawn.lookAt.x, spawn.lookAt.y, spawn.lookAt.z],
101→    });
102→  };
103→
104→  const setNavigationMode = (nextMode = 'inspect') => {
105→    const resolvedMode = nextMode === 'walk' ? 'walk' : 'inspect';
106→    if (navigationMode === resolvedMode) {
107→      emitWalkUiState();
108→      return;
109→    }
110→
111→    if (navigationMode === 'inspect') {
112→      inspectState = inspectNavigation.captureState();
113→    }
114→
115→    if (navigationMode === 'walk') {
116→      saveCurrentWalkPose();
117→    }
118→
119→    navigationMode = resolvedMode;
120→    inspectNavigation.setEnabled(navigationMode === 'inspect');
121→    walkNavigation.setEnabled(navigationMode === 'walk');
122→
123→    if (navigationMode === 'inspect') {
124→      // Derive inspect state from walk camera so the view doesn't jump
125→      const forward = new THREE.Vector3();
126→      camera.getWorldDirection(forward);
127→      const orbitTarget = camera.position.clone().add(forward.multiplyScalar(3000));
128→      const derived = {
129→        position: camera.position.toArray(),
130→        target: orbitTarget.toArray(),
131→      };
132→      if (!inspectNavigation.restoreState(derived)) {
133→        inspectNavigation.resetView();
134→      }
135→    } else {
136→      restoreWalkPose();
137→    }
138→
139→    emitWalkUiState();
140→  };
141→
142→  const renderFrame = (timestamp) => {
143→    timer.update(timestamp);
144→    const deltaSeconds = Math.min(timer.getDelta(), 0.1);
145→    if (navigationMode === 'inspect') {
146→      inspectNavigation.update(deltaSeconds);
147→    } else {
148→      walkNavigation.update(deltaSeconds);
149→    }
150→    renderer.render(scene, camera);
151→    animationFrame = window.requestAnimationFrame(renderFrame);
152→  };
153→
154→  const resize = () => {
155→    const width = container.clientWidth || 1;
156→    const height = container.clientHeight || 1;
157→    camera.aspect = width / height;
158→    camera.updateProjectionMatrix();
159→    renderer.setSize(width, height, false);
160→  };
161→
162→  const resolvePickTarget = (object) => {
163→    let current = object;
164→    while (current) {
165→      if (current.userData?.previewTarget) {
166→        return current.userData.previewTarget;
167→      }
168→      current = current.parent;
169→    }
170→    return null;
171→  };
172→
173→  const pickObjectAt = (clientX, clientY) => {
174→    if (navigationMode !== 'inspect') return;
175→    if (!worldRoot || !pickHandler) return;
176→
177→    const rect = renderer.domElement.getBoundingClientRect();
178→    if (!rect.width || !rect.height) return;
179→
180→    const pointer = new THREE.Vector2(
181→      ((clientX - rect.left) / rect.width) * 2 - 1,
182→      -(((clientY - rect.top) / rect.height) * 2 - 1)
183→    );
184→
185→    raycaster.setFromCamera(pointer, camera);
186→    const hits = raycaster.intersectObject(worldRoot, true);
187→    const seenTargets = new Set();
188→    const targets = [];
189→
190→    for (const hit of hits) {
191→      const target = resolvePickTarget(hit.object);
192→      if (!target) continue;
193→
194→      const key = `${target.floorId || ''}:${target.kind}:${target.sourceId}`;
195→      if (seenTargets.has(key)) continue;
196→      seenTargets.add(key);
197→      targets.push(target);
198→    }
199→
200→    if (!targets.length) {
201→      pickHandler(null);
202→      return;
203→    }
204→
205→    const preferredTarget = pickContext.activeFloorId
206→      ? targets.find((target) => target.floorId === pickContext.activeFloorId) || null
207→      : null;
208→
209→    pickHandler(preferredTarget || targets[0]);
210→  };
211→
212→  const handlePointerDown = (event) => {
213→    if (navigationMode !== 'inspect') {
214→      pointerDown = null;
215→      return;
216→    }
217→
218→    if (event.button !== 0) {
219→      pointerDown = null;
220→      return;
221→    }
222→
223→    pointerDown = {
224→      x: event.clientX,
225→      y: event.clientY,
226→    };
227→  };
228→
229→  const handlePointerCancel = () => {
230→    pointerDown = null;
231→  };
232→
233→  const handlePointerUp = (event) => {
234→    if (navigationMode !== 'inspect') {
235→      pointerDown = null;
236→      return;
237→    }
238→
239→    if (event.button !== 0 || !pointerDown) {
240→      pointerDown = null;
241→      return;
242→    }
243→
244→    const dx = event.clientX - pointerDown.x;
245→    const dy = event.clientY - pointerDown.y;
246→    pointerDown = null;
247→
248→    if (Math.hypot(dx, dy) > CLICK_DISTANCE_THRESHOLD) {
249→      return;
250→    }
251→
252→    pickObjectAt(event.clientX, event.clientY);
253→  };
254→
255→  renderer.domElement.addEventListener('pointerdown', handlePointerDown);
256→  renderer.domElement.addEventListener('pointerup', handlePointerUp);
257→  renderer.domElement.addEventListener('pointercancel', handlePointerCancel);
258→  renderer.domElement.addEventListener('pointerleave', handlePointerCancel);
259→
260→  animationFrame = window.requestAnimationFrame(renderFrame);
261→
262→  return {
263→    setWorld(nextRoot, bounds, groundLevel = 0) {
264→      const hadWorld = !!worldRoot;
265→      const walkPose = navigationMode === 'walk' ? walkNavigation.capturePose() : null;
266→
267→      if (worldRoot) {
268→        scene.remove(worldRoot);
269→        disposeScene(worldRoot, { disposeMaterials: true });
270→      }
271→
272→      if (gridHelper) {
273→        scene.remove(gridHelper);
274→        gridHelper.geometry?.dispose?.();
275→        gridHelper.material?.dispose?.();
276→      }
277→
278→      worldRoot = nextRoot;
279→      currentBounds = descriptorBoundsToWorldBox(bounds);
280→      inspectNavigation.setBounds(currentBounds);
281→      gridHelper = createGrid(bounds, groundLevel);
282→      scene.add(gridHelper);
283→      scene.add(worldRoot);
284→      if (!hadWorld && navigationMode === 'inspect') {
285→        inspectNavigation.resetView();
286→      }
287→
288→      if (walkPose) {
289→        walkNavigation.restorePose(walkPose);
290→      }
291→    },
292→    resetView() {
293→      if (navigationMode === 'walk') {
294→        if (activeFloorContext.floorId) {
295→          walkPoseByFloorId.delete(activeFloorContext.floorId);
296→        }
297→        restoreWalkPose({ forceSpawn: true });
298→        return;
299→      }
300→      inspectNavigation.resetView();
301→    },
302→    fit() {
303→      inspectNavigation.resetView();
304→    },
305→    setProjectionPreset(presetName) {
306→      inspectNavigation.setProjectionPreset(presetName);
307→    },
308→    setPickHandler(handler) {
309→      pickHandler = typeof handler === 'function' ? handler : null;
310→    },
311→    setPickContext(nextContext = {}) {
312→      pickContext = {
313→        ...pickContext,
314→        ...nextContext,
315→      };
316→    },
317→    setNavigationMode,
318→    setActiveFloorContext(nextContext = {}) {
319→      const previousFloorId = activeFloorContext.floorId;
320→      const nextFloorId = nextContext.floorId ?? activeFloorContext.floorId;
321→      const floorChanged = previousFloorId !== nextFloorId;
322→
323→      if (navigationMode === 'walk' && floorChanged && previousFloorId) {
324→        saveCurrentWalkPose();
325→      }
326→
327→      activeFloorContext = {
328→        ...activeFloorContext,
329→        ...nextContext,
330→      };
331→
332→      if (navigationMode === 'walk' && floorChanged) {
333→        restoreWalkPose();
334→      }
335→    },
336→    setWalkUiHandler(handler) {
337→      walkUiHandler = typeof handler === 'function' ? handler : null;
338→      emitWalkUiState();
339→    },
340→    setWalkExitHandler(handler) {
341→      walkExitHandler = typeof handler === 'function' ? handler : null;
342→    },
343→    resize,
344→    dispose() {
345→      window.cancelAnimationFrame(animationFrame);
346→      inspectNavigation.dispose();
347→      walkNavigation.dispose();
348→      renderer.domElement.removeEventListener('pointerdown', handlePointerDown);
349→      renderer.domElement.removeEventListener('pointerup', handlePointerUp);
350→      renderer.domElement.removeEventListener('pointercancel', handlePointerCancel);
351→      renderer.domElement.removeEventListener('pointerleave', handlePointerCancel);
352→
353→      if (worldRoot) {
354→        scene.remove(worldRoot);
355→        disposeScene(worldRoot, { disposeMaterials: true });
356→      }
357→
358→      if (gridHelper) {
359→        scene.remove(gridHelper);
360→        gridHelper.geometry?.dispose?.();
361→        gridHelper.material?.dispose?.();
362→      }
363→
364→      disposeMaterialPalette(materialPalette);
365→      timer.dispose();
366→      renderer.dispose();
367→      renderer.domElement.remove();
368→    },
369→    materialPalette,
370→  };
371→}
