  1→import { formatMeasurement } from '@/annotations/format';
  2→import { getBeamDisplayLabel } from '@/domain/beamLabels';
  3→import { getColumnListLabel } from '@/domain/columnLabels';
  4→import { getLandingDisplayLabel } from '@/domain/landingLabels';
  5→import { getSlabDisplayLabel } from '@/domain/slabLabels';
  6→import { getStairDisplayLabel } from '@/domain/stairLabels';
  7→import { beamLength } from '@/geometry/beamGeometry';
  8→import { slabArea } from '@/geometry/slabGeometry';
  9→import { stairRun, stairTotalRise } from '@/geometry/stairGeometry';
 10→import { wallLength } from '@/geometry/wallGeometry';
 11→
 12→const INSPECTABLE_TYPES = new Set([
 13→  'wall',
 14→  'beam',
 15→  'column',
 16→  'slab',
 17→  'stair',
 18→  'landing',
 19→  'door',
 20→  'window',
 21→  'fixture',
 22→]);
 23→
 24→const TYPE_LABELS = {
 25→  wall: 'Wall',
 26→  beam: 'Beam',
 27→  column: 'Column',
 28→  slab: 'Slab',
 29→  stair: 'Stair',
 30→  landing: 'Landing',
 31→  door: 'Door',
 32→  window: 'Window',
 33→  fixture: 'Fixture',
 34→};
 35→
 36→const FIXTURE_TYPE_LABELS = {
 37→  kitchenTop: 'Kitchen Top',
 38→  toilet: 'Toilet',
 39→  lavatory: 'Lavatory',
 40→  table: 'Table',
 41→  tv: 'TV',
 42→  sofa: 'Sofa',
 43→};
 44→
 45→function mmRow(label, value) {
 46→  return { label, value: formatMeasurement(value || 0) };
 47→}
 48→
 49→function areaRow(label, value) {
 50→  return { label, value: `${(Math.abs(value || 0) / 1_000_000).toFixed(2)} m²` };
 51→}
 52→
 53→function findObjectInFloor(floor, selectedType, selectedId) {
 54→  switch (selectedType) {
 55→    case 'wall':
 56→      return floor.walls?.find((wall) => wall.id === selectedId) || null;
 57→    case 'beam':
 58→      return (floor.beams || []).find((beam) => beam.id === selectedId) || null;
 59→    case 'column':
 60→      return (floor.columns || []).find((column) => column.id === selectedId) || null;
 61→    case 'slab':
 62→      return (floor.slabs || []).find((slab) => slab.id === selectedId) || null;
 63→    case 'stair':
 64→      return (floor.stairs || []).find((stair) => stair.id === selectedId) || null;
 65→    case 'landing':
 66→      return (floor.landings || []).find((landing) => landing.id === selectedId) || null;
 67→    case 'door':
 68→      return floor.doors?.find((door) => door.id === selectedId) || null;
 69→    case 'window':
 70→      return floor.windows?.find((windowItem) => windowItem.id === selectedId) || null;
 71→    case 'fixture':
 72→      return (floor.fixtures || []).find((fixture) => fixture.id === selectedId) || null;
 73→    default:
 74→      return null;
 75→  }
 76→}
 77→
 78→function titleForObject(selectedType, object, floor) {
 79→  switch (selectedType) {
 80→    case 'beam':
 81→      return getBeamDisplayLabel(object, floor.columns || []);
 82→    case 'column':
 83→      return getColumnListLabel(object, floor.columns || []);
 84→    case 'slab':
 85→      return getSlabDisplayLabel(object);
 86→    case 'stair':
 87→      return getStairDisplayLabel(object);
 88→    case 'landing':
 89→      return getLandingDisplayLabel(object);
 90→    case 'wall':
 91→    case 'door':
 92→    case 'window':
 93→      return `${TYPE_LABELS[selectedType]} ${object.id.split('_').pop()}`;
 94→    case 'fixture':
 95→      return FIXTURE_TYPE_LABELS[object.fixtureType] || 'Fixture';
 96→    default:
 97→      return object?.id || TYPE_LABELS[selectedType] || 'Object';
 98→  }
 99→}
100→
101→function rowsForObject(selectedType, object, floor) {
102→  switch (selectedType) {
103→    case 'wall':
104→      return [
105→        mmRow('Length', wallLength(object)),
106→        mmRow('Thickness', object.thickness),
107→        mmRow('Height', object.height),
108→      ];
109→    case 'beam':
110→      return [
111→        mmRow('Span', beamLength(object, floor.columns || [])),
112→        mmRow('Width', object.width),
113→        mmRow('Depth', object.depth),
114→      ];
115→    case 'column':
116→      return [
117→        mmRow('Width', object.width),
118→        mmRow('Depth', object.depth),
119→        mmRow('Height', object.height),
120→      ];
121→    case 'slab':
122→      return [
123→        mmRow('Thickness', object.thickness),
124→        mmRow('Elevation', object.elevation),
125→        areaRow('Area', slabArea(object)),
126→      ];
127→    case 'stair':
128→      return [
129→        mmRow('Width', object.width),
130→        mmRow('Run', stairRun(object)),
131→        mmRow('Total Rise', stairTotalRise(object)),
132→      ];
133→    case 'landing':
134→      return [
135→        mmRow('Width', object.width),
136→        mmRow('Depth', object.depth),
137→        mmRow('Thickness', object.thickness),
138→      ];
139→    case 'door':
140→      return [
141→        mmRow('Width', object.width),
142→        mmRow('Height', object.height),
143→        mmRow('Sill', object.sillHeight),
144→      ];
145→    case 'window':
146→      return [
147→        mmRow('Width', object.width),
148→        mmRow('Height', object.height),
149→        mmRow('Sill', object.sillHeight),
150→      ];
151→    case 'fixture':
152→      return [
153→        mmRow('Width', object.width),
154→        mmRow('Depth', object.depth),
155→      ];
156→    default:
157→      return [];
158→  }
159→}
160→
161→export function isPreviewInspectableType(selectedType) {
162→  return INSPECTABLE_TYPES.has(selectedType);
163→}
164→
165→export function getPreviewInspection(project, selectedType, selectedId) {
166→  if (!selectedId || !isPreviewInspectableType(selectedType)) return null;
167→
168→  for (const floor of project?.floors || []) {
169→    const object = findObjectInFloor(floor, selectedType, selectedId);
170→    if (!object) continue;
171→
172→    return {
173→      id: selectedId,
174→      type: selectedType,
175→      floorId: floor.id,
176→      floorName: floor.name,
177→      title: titleForObject(selectedType, object, floor),
178→      subtitle: `${floor.name} · ${TYPE_LABELS[selectedType]}`,
179→      rows: rowsForObject(selectedType, object, floor),
180→    };
181→  }
182→
183→  return null;
184→}
